import{_ as t,o as s,c as r,ai as a}from"./chunks/framework.LYGRWSbL.js";const g=JSON.parse('{"title":"Poser des questions","description":"","frontmatter":{},"headers":[],"relativePath":"module-3-quotidien/poser-des-questions.md","filePath":"module-3-quotidien/poser-des-questions.md","lastUpdated":1773298982000}'),d={name:"module-3-quotidien/poser-des-questions.md"};function o(i,e,l,n,c,u){return s(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="poser-des-questions" tabindex="-1">Poser des questions <a class="header-anchor" href="#poser-des-questions" aria-label="Permalink to “Poser des questions”">​</a></h1><p><strong>Prérequis :</strong> <a href="./vocabulaire-quotidien.html">Vocabulaire du quotidien</a></p><p><strong>Objectif :</strong> former des questions ouvertes avec les mots interrogatifs allemands.</p><p>Les mots interrogatifs allemands commencent presque tous par <em>W-</em>, d&#39;où leur nom : les <em>W-Fragen</em>.</p><h2 id="les-mots-interrogatifs" tabindex="-1">Les mots interrogatifs <a class="header-anchor" href="#les-mots-interrogatifs" aria-label="Permalink to “Les mots interrogatifs”">​</a></h2><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Mot</th><th class="p-3 text-left font-semibold text-gray-600">Sens</th><th class="p-3 text-left font-semibold text-gray-600">Exemple</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-bold text-green-700">wer</td><td class="p-3 text-gray-600">qui (sujet)</td><td class="p-3 text-gray-500 italic">Wer ist das? - Qui est-ce ?</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-green-700">wen</td><td class="p-3 text-gray-600">qui (objet direct)</td><td class="p-3 text-gray-500 italic">Wen siehst du? - Tu vois qui ?</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-green-700">was</td><td class="p-3 text-gray-600">quoi / que / qu&#39;est-ce que</td><td class="p-3 text-gray-500 italic">Was machst du? - Qu&#39;est-ce que tu fais ?</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-green-700">wo</td><td class="p-3 text-gray-600">ou (lieu statique)</td><td class="p-3 text-gray-500 italic">Wo wohnst du? - Ou habites-tu ?</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-green-700">wohin</td><td class="p-3 text-gray-600">ou (destination)</td><td class="p-3 text-gray-500 italic">Wohin fahrst du? - Ou vas-tu ?</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-green-700">woher</td><td class="p-3 text-gray-600">d&#39;ou (origine)</td><td class="p-3 text-gray-500 italic">Woher kommst du? - Tu viens d&#39;ou ?</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-green-700">wann</td><td class="p-3 text-gray-600">quand</td><td class="p-3 text-gray-500 italic">Wann kommt der Zug? - Le train arrive quand ?</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-green-700">wie</td><td class="p-3 text-gray-600">comment / combien</td><td class="p-3 text-gray-500 italic">Wie heißt du? - Comment tu t&#39;appelles ?</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-green-700">wie viel</td><td class="p-3 text-gray-600">combien (quantite)</td><td class="p-3 text-gray-500 italic">Wie viel kostet das? - Ca coute combien ?</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-green-700">warum</td><td class="p-3 text-gray-600">pourquoi</td><td class="p-3 text-gray-500 italic">Warum lernst du Deutsch? - Pourquoi tu apprends l&#39;allemand ?</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-green-700">welch-</td><td class="p-3 text-gray-600">quel / quelle</td><td class="p-3 text-gray-500 italic">Welchen Zug nimmst du? - Quel train tu prends ?</td></tr></tbody></table></div><div class="warning custom-block"><p class="custom-block-title">wo / wohin / woher - trois mots pour &quot;ou&quot;</p><p>C&#39;est le point le plus déroutant pour les francophones. L&#39;allemand distingue le lieu statique (<em>wo</em> - où est-ce ?), la destination (<em>wohin</em> - vers où ?) et l&#39;origine (<em>woher</em> - d&#39;où ?). Cette distinction est obligatoire et change le verbe utilisé : <em>sein</em> pour <em>wo</em>, <em>gehen/fahren/kommen</em> pour <em>wohin/woher</em>.</p></div><h2 id="structure-de-la-w-frage" tabindex="-1">Structure de la W-Frage <a class="header-anchor" href="#structure-de-la-w-frage" aria-label="Permalink to “Structure de la W-Frage”">​</a></h2><p>La règle V2 s&#39;applique : le mot interrogatif est en position 1, le verbe en position 2.</p><div class="mt-4 p-4 rounded-xl border border-gray-200"><div class="grid grid-cols-3 gap-2 text-center"><div class="bg-orange-50 border border-orange-200 rounded p-2"><div class="text-xs text-orange-500 font-medium">Position 1</div><div class="font-bold text-orange-800">Wo</div></div><div class="bg-green-50 border border-green-200 rounded p-2"><div class="text-xs text-green-500 font-medium">Position 2 - Verbe</div><div class="font-bold text-green-800">wohnst</div></div><div class="bg-blue-50 border border-blue-200 rounded p-2"><div class="text-xs text-blue-500 font-medium">Sujet</div><div class="font-bold text-blue-800">du ?</div></div></div><div class="text-sm text-gray-500 text-center mt-3">Ou habites-tu ?</div></div><h2 id="wer-se-decline-aussi" tabindex="-1">wer se décline aussi <a class="header-anchor" href="#wer-se-decline-aussi" aria-label="Permalink to “wer se décline aussi”">​</a></h2><p><em>Wer</em> (qui) se décline comme le masculin singulier pour le cas :</p><ul><li><em>Wer</em> = nominatif : <em>Wer kommt?</em> - Qui vient ?</li><li><em>Wen</em> = accusatif : <em>Wen rufst du an?</em> - Tu appelles qui ?</li><li><em>Wem</em> = datif : <em>Wem gibst du das?</em> - A qui tu donnes ca ?</li></ul><div class="tip custom-block"><p class="custom-block-title">welch- suit la déclinaison des articles</p><p><em>Welcher</em> (masculin nom.), <em>welche</em> (féminin), <em>welches</em> (neutre), <em>welchen</em> (masculin acc.) - la terminaison change comme pour <em>ein/eine</em>. Dans le doute, utilisé <em>welche</em> qui fonctionne pour le féminin et le pluriel.</p></div>',14)])])}const p=t(d,[["render",o]]);export{g as __pageData,p as default};
